INSERT INTO `v1_409156a8daa0060ac935dd09b63850bbca5190b117f5332dd3b2bc027206c4ee` VALUES (190802, 2, 0.0, 53, 3.414, -416.5, "ミッションをクリアすると、\n報酬がもらえますよ！\n頑張ってください", "カリン", "2021/10/27 14:59:59", 10077001, 10077, "2021/10/18 12:00:00", 1, 1);
INSERT INTO `v1_409156a8daa0060ac935dd09b63850bbca5190b117f5332dd3b2bc027206c4ee` VALUES (190802, 2, 0.0, 53, 3.099, -416.5, "ミッションをクリアして、\n報酬をゲットしましょう！", "カリン", "2021/10/27 14:59:59", 10077002, 10077, "2021/10/18 12:00:00", 2, 1);
INSERT INTO `v1_409156a8daa0060ac935dd09b63850bbca5190b117f5332dd3b2bc027206c4ee` VALUES (190802, 2, 0.0, 54, 2.801, -416.5, "受け取ることができる\n報酬があるようです\n確認してみてください", "カリン", "2021/10/27 14:59:59", 10077003, 10077, "2021/10/18 12:00:00", 3, 1);
INSERT INTO `v1_409156a8daa0060ac935dd09b63850bbca5190b117f5332dd3b2bc027206c4ee` VALUES (190802, 2, 0.0, 54, 0.0, -416.5, "報酬がもらえますよ！\nチェックしてみてください", "カリン", "2021/10/27 14:59:59", 10077004, 10077, "2021/10/18 12:00:00", 4, 2);
INSERT INTO `v1_409156a8daa0060ac935dd09b63850bbca5190b117f5332dd3b2bc027206c4ee` VALUES (190802, 1, 0.0, 57, 0.0, -416.5, "イベントお疲れ様です！\n皆さんのご活躍ぶりには\nいつも感謝しています", "カリン", "2021/10/27 14:59:59", 10077005, 10077, "2021/10/18 12:00:00", 5, 1);
INSERT INTO `v1_409156a8daa0060ac935dd09b63850bbca5190b117f5332dd3b2bc027206c4ee` VALUES (190802, 2, 0.0, 55, 5.506, -363.0, "ギルド管理協会です！\n討伐証をお持ちでしたら、\n報酬交換できますよ", "カリン", "2021/10/27 14:59:59", 10077006, 10077, "2021/10/18 12:00:00", 1, 1);
INSERT INTO `v1_409156a8daa0060ac935dd09b63850bbca5190b117f5332dd3b2bc027206c4ee` VALUES (190802, 1, 0.0, 55, 1.216, -363.0, "お疲れ様です！\nここでは、討伐証と報酬を\n交換することができます！", "カリン", "2021/10/27 14:59:59", 10077007, 10077, "2021/10/18 12:00:00", 2, 2);
INSERT INTO `v1_409156a8daa0060ac935dd09b63850bbca5190b117f5332dd3b2bc027206c4ee` VALUES (190802, 1, 0.0, 56, 1.539, -363.0, "お疲れ様でした\n討伐証の交換、\nお忘れないように！", "カリン", "2021/10/27 14:59:59", 10077008, 10077, "2021/10/18 12:00:00", 3, 2);
INSERT INTO `v1_409156a8daa0060ac935dd09b63850bbca5190b117f5332dd3b2bc027206c4ee` VALUES (190802, 1, 0.0, 56, 1.875, -363.0, "終わっちゃいましたねー\n討伐証は努力の証！\n報酬と交換しましょう！", "カリン", "2021/10/27 14:59:59", 10077009, 10077, "2021/10/18 12:00:00", 4, 2);
