INSERT INTO `v1_409156a8daa0060ac935dd09b63850bbca5190b117f5332dd3b2bc027206c4ee` VALUES (190801, 2, 0.0, 54, 2.801, -416.5, "受け取ることができる\n報酬があるようです\n確認してみてください", "カリン", "2030/01/01 14:59:59", 20047003, 20047, "2023/11/16 15:00:00", 3, 1);
INSERT INTO `v1_409156a8daa0060ac935dd09b63850bbca5190b117f5332dd3b2bc027206c4ee` VALUES (190801, 2, 0.0, 54, 0.0, -416.5, "報酬がもらえますよ！\nチェックしてみてください", "カリン", "2030/01/01 14:59:59", 20047004, 20047, "2023/11/16 15:00:00", 4, 2);
INSERT INTO `v1_409156a8daa0060ac935dd09b63850bbca5190b117f5332dd3b2bc027206c4ee` VALUES (190801, 1, 0.0, 57, 0.0, -416.5, "イベントお疲れ様です！\n皆さんのご活躍ぶりには\nいつも感謝しています", "カリン", "2030/01/01 14:59:59", 20047005, 20047, "2023/11/16 15:00:00", 5, 1);
