INSERT INTO `v1_409156a8daa0060ac935dd09b63850bbca5190b117f5332dd3b2bc027206c4ee` VALUES (190801, 2, 0.0, 54, 0.0, -416.5, "報酬がもらえますよ！\nチェックしてみてください", "カリン", "2030/01/01 14:59:59", 20077004, 20077, "2026/05/16 15:00:00", 4, 2);
INSERT INTO `v1_409156a8daa0060ac935dd09b63850bbca5190b117f5332dd3b2bc027206c4ee` VALUES (190801, 1, 0.0, 57, 0.0, -416.5, "イベントお疲れ様です！\n皆さんのご活躍ぶりには\nいつも感謝しています", "カリン", "2030/01/01 14:59:59", 20077005, 20077, "2026/05/16 15:00:00", 5, 1);
INSERT INTO `v1_409156a8daa0060ac935dd09b63850bbca5190b117f5332dd3b2bc027206c4ee` VALUES (190801, 2, 0.0, 55, 5.506, -363.0, "ギルド管理協会です！\n討伐証をお持ちでしたら、\n報酬交換できますよ", "カリン", "2030/01/01 14:59:59", 20077006, 20077, "2026/05/16 15:00:00", 1, 1);
INSERT INTO `v1_409156a8daa0060ac935dd09b63850bbca5190b117f5332dd3b2bc027206c4ee` VALUES (190801, 1, 0.0, 55, 1.216, -363.0, "お疲れ様です！\nここでは、討伐証と報酬を\n交換することができます！", "カリン", "2030/01/01 14:59:59", 20077007, 20077, "2026/05/16 15:00:00", 2, 2);
INSERT INTO `v1_409156a8daa0060ac935dd09b63850bbca5190b117f5332dd3b2bc027206c4ee` VALUES (190801, 1, 0.0, 56, 1.539, -363.0, "お疲れ様でした\n討伐証の交換、\nお忘れないように！", "カリン", "2030/01/01 14:59:59", 20077008, 20077, "2026/05/16 15:00:00", 3, 2);
INSERT INTO `v1_409156a8daa0060ac935dd09b63850bbca5190b117f5332dd3b2bc027206c4ee` VALUES (190801, 1, 0.0, 56, 1.875, -363.0, "終わっちゃいましたねー\n討伐証は努力の証！\n報酬と交換しましょう！", "カリン", "2030/01/01 14:59:59", 20077009, 20077, "2026/05/16 15:00:00", 4, 2);
